import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type PartOfSpeech = 'noun' | 'verb' | 'adj' | 'adv' | 'other';

export interface Token {
  id: string;
  text: string;
  pos: PartOfSpeech;
  isSeparator?: boolean; // spaces, punctuation, newlines
}

export interface Essay {
  id: string;
  title: string;
  rawContent: string;
  tokens: Token[];
  isAnalyzed: boolean;
  createdAt: number;
}

export enum PracticeMode {
  READ = 'READ',
  LEVEL_1 = 'LEVEL_1', // Nouns
  LEVEL_2 = 'LEVEL_2', // Nouns + Verbs
  LEVEL_3 = 'LEVEL_3', // Nouns + Verbs + Adj + Adv
}

export interface UserAnswers {
  [tokenId: string]: string;
}

export interface VerificationResult {
  [tokenId: string]: boolean;
}

export const INITIAL_ESSAY_TITLE = "Unit 8: Pets";

export const INITIAL_ESSAY_CONTENT = `Recently, more and more young people like to keep pets. Some of them think their pets are part of the family.
People keep pets mainly because they are lovely and can bring happiness. Pets are good companions, especially for the elderly and children, helping them feel less lonely. Playing with pets after school or work can help us relax. Moreover, taking care of pets teaches us responsibility and how to care for others.
However, keeping pets also has its downsides. Pets can be noisy at night, which may disturb neighbors. Some pets might even attack people. Besides, they need to be cleaned often, and their waste can cause environmental problems. The cost of food and medical care for pets can also be high.
In my opinion, keeping pets is a good idea if we can take proper care of them. We should make sure they are clean, healthy, and well-trained. By this way, pets can bring us joy without causing trouble to others.`;

// Utility to handle Gemini raw PCM audio decoding

let audioContext: AudioContext | null = null;

export const getAudioContext = (): AudioContext => {
  if (!audioContext) {
    audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({
      sampleRate: 24000, // Gemini TTS standard sample rate
    });
  }
  return audioContext;
};

function atob_safe(base64: string) {
  const binaryString = window.atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

export async function decodeAudioData(
  base64String: string,
  ctx: AudioContext
): Promise<AudioBuffer> {
  const bytes = atob_safe(base64String);
  // Gemini sends raw PCM (Int16), not a WAV file.
  // We need to convert Int16 -> Float32 manually for AudioBuffer
  const dataInt16 = new Int16Array(bytes.buffer);
  const numChannels = 1; // Usually mono
  const sampleRate = 24000;

  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      // Normalize Int16 to Float32 [-1.0, 1.0]
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

export async function playAudioBuffer(buffer: AudioBuffer): Promise<void> {
  const ctx = getAudioContext();
  // Resume context if suspended (browser autoplay policy)
  if (ctx.state === 'suspended') {
    await ctx.resume();
  }

  return new Promise((resolve) => {
    const source = ctx.createBufferSource();
    source.buffer = buffer;
    source.connect(ctx.destination);
    source.onended = () => {
        resolve();
    };
    source.start();
  });
}

import { GoogleGenAI, Modality, Type } from "@google/genai";
import { Token } from "../types";

// Note: In a production app, never expose API keys on the client side.
// This is for demonstration purposes or personal tools.
const getClient = () => {
    const apiKey = process.env.API_KEY;
    if (!apiKey) {
        throw new Error("API Key is missing. Please set process.env.API_KEY.");
    }
    return new GoogleGenAI({ apiKey });
};

export const analyzeTextForMemorization = async (text: string): Promise<Token[]> => {
  const ai = getClient();

  // We need a structured response to identify Nouns, Verbs, Adjectives, Adverbs
  // while preserving the EXACT structure of the text (including punctuation) for reconstruction.
  const prompt = `
    Analyze the following English text for a fill-in-the-blank exercise.
    Break the text down into a sequence of tokens that can perfectly reconstruct the original text.

    For each token, assign a 'pos' (Part of Speech) from these categories:
    - 'noun'
    - 'verb' (including auxiliary verbs like 'is', 'are', 'can')
    - 'adj' (adjective)
    - 'adv' (adverb)
    - 'other' (prepositions, pronouns like 'it', 'they', conjunctions, articles, etc.)

    If the token is punctuation, space, or newline, label 'pos' as 'other' and mark 'isSeparator' as true.

    Text to analyze:
    """${text}"""
  `;

  try {
    const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: {
            responseMimeType: "application/json",
            responseSchema: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: {
                        text: { type: Type.STRING },
                        pos: { type: Type.STRING, enum: ['noun', 'verb', 'adj', 'adv', 'other'] },
                        isSeparator: { type: Type.BOOLEAN }
                    },
                    required: ['text', 'pos']
                }
            }
        }
    });

    const tokens = JSON.parse(response.text || '[]');

    // Add unique IDs to tokens for React keys
    return tokens.map((t: any, idx: number) => ({
        ...t,
        id: `token-${idx}-${Date.now()}`
    }));

  } catch (error) {
    console.error("Gemini Analysis Failed:", error);
    throw error;
  }
};

export const generateSpeech = async (text: string): Promise<string> => {
    const ai = getClient();

    try {
        const response = await ai.models.generateContent({
            model: "gemini-2.5-flash-preview-tts",
            contents: [{ parts: [{ text }] }],
            config: {
                responseModalities: [Modality.AUDIO],
                speechConfig: {
                    voiceConfig: {
                        prebuiltVoiceConfig: { voiceName: 'Fenrir' }, // Deep, clear voice suitable for reading
                    },
                },
            },
        });

        const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
        if (!base64Audio) {
            throw new Error("No audio data received from Gemini.");
        }
        return base64Audio;
    } catch (error) {
        console.error("Gemini TTS Failed:", error);
        throw error;
    }
};

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { v4 as uuidv4 } from 'uuid'; // Simple ID generator logic can be replaced if library not available, but assuming environment supports basic JS.
import { INITIAL_ESSAY_TITLE, INITIAL_ESSAY_CONTENT } from './constants';
import { Essay, PracticeMode, Token, UserAnswers, VerificationResult } from './types';
import { analyzeTextForMemorization, generateSpeech } from './services/geminiService';
import { decodeAudioData, playAudioBuffer, getAudioContext } from './services/audioService';

// --- Icons ---
const PlayIcon = () => (
  <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polygon points="5 3 19 12 5 21 5 3"></polygon></svg>
);
const PauseIcon = () => (
    <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><rect x="6" y="4" width="4" height="16"></rect><rect x="14" y="4" width="4" height="16"></rect></svg>
);
const PlusIcon = () => (
  <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><line x1="12" y1="5" x2="12" y2="19"></line><line x1="5" y1="12" x2="19" y2="12"></line></svg>
);
const TrashIcon = () => (
  <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polyline points="3 6 5 6 21 6"></polyline><path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"></path></svg>
);
const CheckIcon = () => (
  <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polyline points="20 6 9 17 4 12"></polyline></svg>
);

const LoadingSpinner = () => (
    <div className="animate-spin rounded-full h-5 w-5 border-b-2 border-white"></div>
);

// --- Helpers ---
const generateId = () => Date.now().toString(36) + Math.random().toString(36).substr(2);

// --- Components ---

export default function App() {
  const [essays, setEssays] = useState<Essay[]>([]);
  const [activeEssayId, setActiveEssayId] = useState<string | null>(null);
  const [mode, setMode] = useState<PracticeMode>(PracticeMode.READ);

  // State for adding new essay
  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [newTitle, setNewTitle] = useState('');
  const [newContent, setNewContent] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);

  // State for practice
  const [answers, setAnswers] = useState<UserAnswers>({});
  const [results, setResults] = useState<VerificationResult | null>(null);
  const [score, setScore] = useState<number | null>(null);

  // State for Audio
  const [isPlaying, setIsPlaying] = useState(false);
  const [isLoadingAudio, setIsLoadingAudio] = useState(false);

  // Initialization
  useEffect(() => {
    const savedEssays = localStorage.getItem('memomaster_essays');
    if (savedEssays) {
      const parsed = JSON.parse(savedEssays);
      setEssays(parsed);
      if (parsed.length > 0) setActiveEssayId(parsed[0].id);
    } else {
      // Load initial essay
      const initialId = generateId();
      const initialEssay: Essay = {
        id: initialId,
        title: INITIAL_ESSAY_TITLE,
        rawContent: INITIAL_ESSAY_CONTENT,
        tokens: [],
        isAnalyzed: false,
        createdAt: Date.now()
      };
      setEssays([initialEssay]);
      setActiveEssayId(initialId);
      analyzeEssay(initialEssay);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Save to local storage whenever essays change
  useEffect(() => {
    if (essays.length > 0) {
      localStorage.setItem('memomaster_essays', JSON.stringify(essays));
    }
  }, [essays]);

  // Reset answers when mode or essay changes
  useEffect(() => {
    setAnswers({});
    setResults(null);
    setScore(null);
    setIsPlaying(false);
  }, [mode, activeEssayId]);

  const activeEssay = essays.find(e => e.id === activeEssayId);

  const analyzeEssay = async (essay: Essay) => {
    setIsProcessing(true);
    try {
      const tokens = await analyzeTextForMemorization(essay.rawContent);
      setEssays(prev => prev.map(e => e.id === essay.id ? { ...e, tokens, isAnalyzed: true } : e));
    } catch (err) {
      alert("Failed to analyze text. Please check API Key and try again.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleAddEssay = async () => {
    if (!newTitle.trim() || !newContent.trim()) return;

    setIsProcessing(true);
    try {
      const tokens = await analyzeTextForMemorization(newContent);
      const newEssay: Essay = {
        id: generateId(),
        title: newTitle,
        rawContent: newContent,
        tokens,
        isAnalyzed: true,
        createdAt: Date.now()
      };
      setEssays(prev => [...prev, newEssay]);
      setActiveEssayId(newEssay.id);
      setIsAddModalOpen(false);
      setNewTitle('');
      setNewContent('');
      setMode(PracticeMode.READ);
    } catch (err) {
      alert("Failed to process essay. Ensure API Key is set.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleDeleteEssay = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (window.confirm("Are you sure you want to delete this essay?")) {
        const newEssays = essays.filter(ex => ex.id !== id);
        setEssays(newEssays);
        localStorage.setItem('memomaster_essays', JSON.stringify(newEssays));
        if (activeEssayId === id) {
            setActiveEssayId(newEssays.length > 0 ? newEssays[0].id : null);
        }
    }
  };

  const handlePlayAudio = async () => {
    if (!activeEssay) return;
    if (isPlaying) {
        // Since we are using fire-and-forget buffer playback, stopping is tricky without keeping track of the source node.
        // For this demo, we assume the user lets it finish or reloads if they desperately need to stop.
        // But functionally, we toggle the UI state.
        setIsPlaying(false);
        return;
    }

    setIsLoadingAudio(true);
    try {
        const base64 = await generateSpeech(activeEssay.rawContent);
        const ctx = getAudioContext();
        const buffer = await decodeAudioData(base64, ctx);
        setIsLoadingAudio(false);
        setIsPlaying(true);
        await playAudioBuffer(buffer);
        setIsPlaying(false);
    } catch (err) {
        console.error(err);
        alert("Audio generation failed.");
        setIsLoadingAudio(false);
        setIsPlaying(false);
    }
  };

  const isTokenHidden = (token: Token) => {
    if (token.isSeparator) return false;

    const p = token.pos;
    if (mode === PracticeMode.READ) return false;

    // Level 1: Nouns
    if (mode === PracticeMode.LEVEL_1) {
        return p === 'noun';
    }

    // Level 2: Nouns + Verbs
    if (mode === PracticeMode.LEVEL_2) {
        return p === 'noun' || p === 'verb';
    }

    // Level 3: Nouns + Verbs + Adj + Adv
    if (mode === PracticeMode.LEVEL_3) {
        return p === 'noun' || p === 'verb' || p === 'adj' || p === 'adv';
    }

    return false;
  };

  const handleInputChange = (id: string, value: string) => {
    setAnswers(prev => ({ ...prev, [id]: value }));
  };

  const checkAnswers = () => {
    if (!activeEssay) return;

    let correctCount = 0;
    let totalHidden = 0;
    const newResults: VerificationResult = {};

    activeEssay.tokens.forEach(token => {
        if (isTokenHidden(token)) {
            totalHidden++;
            const userVal = (answers[token.id] || "").trim().toLowerCase();
            const correctVal = token.text.trim().toLowerCase();

            // Allow for minor punctuation mismatch if user typed it, though usually we just check the word
            // Let's strip punctuation from both for comparison to be safe
            const cleanUser = userVal.replace(/[.,/#!$%^&*;:{}=\-_`~()]/g,"");
            const cleanCorrect = correctVal.replace(/[.,/#!$%^&*;:{}=\-_`~()]/g,"");

            const isCorrect = cleanUser === cleanCorrect;
            newResults[token.id] = isCorrect;
            if (isCorrect) correctCount++;
        }
    });

    setResults(newResults);
    setScore(totalHidden === 0 ? 100 : Math.round((correctCount / totalHidden) * 100));
  };

  // --- Render Helpers ---

  const renderToken = (token: Token) => {
    if (token.isSeparator) {
        // Replace newlines with <br/>
        if (token.text.includes('\n')) {
             return <br key={token.id} />;
        }
        return <span key={token.id} className="whitespace-pre">{token.text}</span>;
    }

    const hidden = isTokenHidden(token);

    if (hidden) {
        const isChecked = results !== null;
        const isCorrect = isChecked ? results[token.id] : undefined;

        let borderClass = "border-gray-300 focus:border-blue-500";
        let textClass = "text-gray-800";

        if (isChecked) {
            borderClass = isCorrect ? "border-green-500 bg-green-50" : "border-red-500 bg-red-50";
            textClass = isCorrect ? "text-green-700" : "text-red-700";
        }

        // Calculate width approx based on char length, min 30px
        const width = Math.max(30, token.text.length * 10) + "px";

        return (
            <span key={token.id} className="inline-block mx-1 relative group">
                <input
                    type="text"
                    value={answers[token.id] || ''}
                    onChange={(e) => handleInputChange(token.id, e.target.value)}
                    className={`border-b-2 outline-none text-center bg-transparent transition-colors px-1 ${borderClass} ${textClass}`}
                    style={{ width }}
                    autoComplete="off"
                    autoCorrect="off"
                    autoCapitalize="off"
                />
                {isChecked && !isCorrect && (
                     <span className="absolute -top-6 left-1/2 -translate-x-1/2 bg-black text-white text-xs px-2 py-1 rounded opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none whitespace-nowrap z-10">
                        {token.text}
                     </span>
                )}
            </span>
        );
    }

    return <span key={token.id} className="text-gray-800">{token.text}</span>;
  };

  // --- Main Render ---

  return (
    <div className="flex h-screen overflow-hidden bg-gray-50">

      {/* Sidebar */}
      <aside className="w-64 bg-white border-r border-gray-200 flex flex-col hidden md:flex">
        <div className="p-4 border-b border-gray-100 flex items-center justify-between">
            <h1 className="font-bold text-xl text-blue-600 tracking-tight">MemoMaster AI</h1>
        </div>

        <div className="flex-1 overflow-y-auto p-2 space-y-1 no-scrollbar">
            {essays.map(essay => (
                <div
                    key={essay.id}
                    onClick={() => setActiveEssayId(essay.id)}
                    className={`group flex items-center justify-between p-3 rounded-lg cursor-pointer transition-all ${
                        activeEssayId === essay.id ? 'bg-blue-50 text-blue-700 font-medium' : 'hover:bg-gray-100 text-gray-600'
                    }`}
                >
                    <span className="truncate pr-2">{essay.title}</span>
                    <button 
                        onClick={(e) => handleDeleteEssay(essay.id, e)}
                        className="text-gray-400 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-opacity"
                    >
                        <TrashIcon />
                    </button>
                </div>
            ))}
        </div>

        <div className="p-4 border-t border-gray-100">
            <button
                onClick={() => setIsAddModalOpen(true)}
                className="w-full flex items-center justify-center gap-2 bg-blue-600 hover:bg-blue-700 text-white py-2 px-4 rounded-lg font-medium transition-colors shadow-sm"
            >
                <PlusIcon /> New Essay
            </button>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col h-full relative">

        {/* Mobile Header */}
        <div className="md:hidden bg-white border-b p-4 flex justify-between items-center">
             <h1 className="font-bold text-lg text-blue-600">MemoMaster AI</h1>
             <button onClick={() => setIsAddModalOpen(true)} className="text-blue-600">
                 <PlusIcon />
             </button>
        </div>

        {/* Top Control Bar */}
        {activeEssay && (
        <header className="bg-white border-b border-gray-200 px-6 py-4 flex flex-col sm:flex-row sm:items-center justify-between gap-4 shadow-sm z-10">
            <div>
                <h2 className="text-2xl font-bold text-gray-800 truncate max-w-md">{activeEssay.title}</h2>
                <div className="text-sm text-gray-400 mt-1">
                    {activeEssay.tokens.length > 0 ? `${activeEssay.tokens.filter(t=>!t.isSeparator).length} words` : 'Processing...'}
                </div>
            </div>

            <div className="flex items-center gap-2 bg-gray-100 p-1 rounded-lg self-start sm:self-auto">
                <button
                    onClick={() => setMode(PracticeMode.READ)}
                    className={`px-4 py-1.5 rounded-md text-sm font-medium transition-all ${mode === PracticeMode.READ ? 'bg-white text-blue-600 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}
                >
                    Read
                </button>
                <button
                    onClick={() => setMode(PracticeMode.LEVEL_1)}
                    className={`px-4 py-1.5 rounded-md text-sm font-medium transition-all ${mode === PracticeMode.LEVEL_1 ? 'bg-white text-blue-600 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}
                >
                    Step 1 (N)
                </button>
                <button
                    onClick={() => setMode(PracticeMode.LEVEL_2)}
                    className={`px-4 py-1.5 rounded-md text-sm font-medium transition-all ${mode === PracticeMode.LEVEL_2 ? 'bg-white text-blue-600 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}
                >
                    Step 2 (V)
                </button>
                <button
                    onClick={() => setMode(PracticeMode.LEVEL_3)}
                    className={`px-4 py-1.5 rounded-md text-sm font-medium transition-all ${mode === PracticeMode.LEVEL_3 ? 'bg-white text-blue-600 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}
                >
                    Step 3 (All)
                </button>
            </div>
        </header>
        )}

        {/* Text Area */}
        <div className="flex-1 overflow-y-auto p-4 sm:p-8 bg-gray-50">
            <div className="max-w-3xl mx-auto bg-white rounded-2xl shadow-sm border border-gray-100 min-h-[50vh] p-6 sm:p-10 leading-loose text-lg text-gray-800">
                {activeEssay ? (
                    !activeEssay.isAnalyzed ? (
                        <div className="flex flex-col items-center justify-center h-40 text-gray-400">
                           <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-500 mb-2"></div>
                           <p>Analyzing grammar structure...</p>
                        </div>
                    ) : (
                        <div className="space-y-4">
                            <div className="font-serif leading-9">
                                {activeEssay.tokens.map(token => renderToken(token))}
                            </div>
                        </div>
                    )
                ) : (
                   <div className="text-center text-gray-400 mt-20">No essay selected. Create one to start.</div>
                )}
            </div>
        </div>

        {/* Bottom Sticky Action Bar */}
        {activeEssay && activeEssay.isAnalyzed && (
            <div className="absolute bottom-6 left-0 right-0 flex justify-center gap-4 px-4 pointer-events-none">
                <div className="bg-white/90 backdrop-blur-md shadow-lg border border-gray-200 rounded-full p-2 flex items-center gap-4 pointer-events-auto pr-6">

                    {/* Audio Control */}
                    <button 
                        onClick={handlePlayAudio}
                        disabled={isLoadingAudio}
                        className="w-10 h-10 rounded-full bg-gray-100 hover:bg-gray-200 flex items-center justify-center text-gray-700 transition-colors"
                        title="Read Aloud (Gemini TTS)"
                    >
                        {isLoadingAudio ? <LoadingSpinner /> : isPlaying ? <PauseIcon /> : <PlayIcon />}
                    </button>

                    <div className="w-px h-6 bg-gray-300"></div>

                    {/* Check Action (Only in practice modes) */}
                    {mode !== PracticeMode.READ && (
                         <div className="flex items-center gap-4">
                            {score !== null && (
                                <div className={`font-bold text-lg ${score > 80 ? 'text-green-600' : 'text-orange-500'}`}>
                                    {score}% Correct
                                </div>
                            )}
                            <button
                                onClick={checkAnswers}
                                className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-5 py-2 rounded-full font-medium shadow-md transition-transform active:scale-95"
                            >
                                <CheckIcon /> Check Answers
                            </button>
                         </div>
                    )}

                    {mode === PracticeMode.READ && (
                        <span className="text-sm text-gray-500 font-medium px-2">Read Mode</span>
                    )}

                </div>
            </div>
        )}

        {/* Add Modal */}
        {isAddModalOpen && (
            <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/40 backdrop-blur-sm p-4">
                <div className="bg-white rounded-xl shadow-2xl w-full max-w-lg overflow-hidden">
                    <div className="p-6">
                        <h3 className="text-xl font-bold text-gray-800 mb-4">Add New Essay</h3>
                        <div className="space-y-4">
                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Title</label>
                                <input
                                    type="text"
                                    value={newTitle}
                                    onChange={e => setNewTitle(e.target.value)}
                                    className="w-full border border-gray-300 rounded-lg px-4 py-2 focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none"
                                    placeholder="e.g. Unit 1: My School"
                                />
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Content</label>
                                <textarea
                                    value={newContent}
                                    onChange={e => setNewContent(e.target.value)}
                                    rows={8}
                                    className="w-full border border-gray-300 rounded-lg px-4 py-2 focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none resize-none"
                                    placeholder="Paste your essay here..."
                                />
                            </div>
                        </div>
                    </div>
                    <div className="bg-gray-50 px-6 py-4 flex justify-end gap-3 border-t border-gray-100">
                        <button
                            onClick={() => setIsAddModalOpen(false)}
                            className="px-4 py-2 text-gray-600 hover:bg-gray-200 rounded-lg font-medium transition-colors"
                        >
                            Cancel
                        </button>
                        <button
                            onClick={handleAddEssay}
                            disabled={isProcessing || !newTitle || !newContent}
                            className={`px-4 py-2 bg-blue-600 text-white rounded-lg font-medium shadow-sm transition-all flex items-center gap-2 ${
                                (isProcessing || !newTitle || !newContent) ? 'opacity-50 cursor-not-allowed' : 'hover:bg-blue-700'
                            }`}
                        >
                            {isProcessing ? <><LoadingSpinner /> Processing...</> : 'Add Essay'}
                        </button>
                    </div>
                </div>
            </div>
        )}

      </main>
    </div>
  );
}

// Utility to handle Gemini raw PCM audio decoding

let audioContext: AudioContext | null = null;
let currentSource: AudioBufferSourceNode | null = null;

export const getAudioContext = (): AudioContext => {
  if (!audioContext) {
    audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({
      sampleRate: 24000, // Gemini TTS standard sample rate
    });
  }
  return audioContext;
};

function atob_safe(base64: string) {
  const binaryString = window.atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

export async function decodeAudioData(
  base64String: string,
  ctx: AudioContext
): Promise<AudioBuffer> {
  const bytes = atob_safe(base64String);
  // Gemini sends raw PCM (Int16), not a WAV file.
  // We need to convert Int16 -> Float32 manually for AudioBuffer
  const dataInt16 = new Int16Array(bytes.buffer);
  const numChannels = 1; // Usually mono
  const sampleRate = 24000;

  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      // Normalize Int16 to Float32 [-1.0, 1.0]
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

export function stopAudio() {
    if (currentSource) {
        try {
            currentSource.stop();
        } catch (e) {
            // Ignore errors if already stopped
        }
        currentSource = null;
    }
}

export async function playAudioBuffer(buffer: AudioBuffer): Promise<void> {
  const ctx = getAudioContext();
  // Resume context if suspended (browser autoplay policy)
  if (ctx.state === 'suspended') {
    await ctx.resume();
  }

  // Stop any currently playing audio before starting new one
  stopAudio();

  return new Promise((resolve) => {
    const source = ctx.createBufferSource();
    source.buffer = buffer;
    source.connect(ctx.destination);

    currentSource = source;

    source.onended = () => {
        if (currentSource === source) {
            currentSource = null;
        }
        resolve();
    };
    source.start();
  });
}

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { v4 as uuidv4 } from 'uuid'; // Simple ID generator logic can be replaced if library not available, but assuming environment supports basic JS.
import { INITIAL_ESSAY_TITLE, INITIAL_ESSAY_CONTENT } from './constants';
import { Essay, PracticeMode, Token, UserAnswers, VerificationResult } from './types';
import { analyzeTextForMemorization, generateSpeech } from './services/geminiService';
import { decodeAudioData, playAudioBuffer, getAudioContext, stopAudio } from './services/audioService';

// --- Icons ---
const PlayIcon = () => (
  <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polygon points="5 3 19 12 5 21 5 3"></polygon></svg>
);
const PauseIcon = () => (
    <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><rect x="6" y="4" width="4" height="16"></rect><rect x="14" y="4" width="4" height="16"></rect></svg>
);
const PlusIcon = () => (
  <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><line x1="12" y1="5" x2="12" y2="19"></line><line x1="5" y1="12" x2="19" y2="12"></line></svg>
);
const TrashIcon = () => (
  <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polyline points="3 6 5 6 21 6"></polyline><path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"></path></svg>
);
const CheckIcon = () => (
  <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polyline points="20 6 9 17 4 12"></polyline></svg>
);

const LoadingSpinner = () => (
    <div className="animate-spin rounded-full h-5 w-5 border-b-2 border-white"></div>
);

// --- Helpers ---
const generateId = () => Date.now().toString(36) + Math.random().toString(36).substr(2);

// --- Components ---

export default function App() {
  const [essays, setEssays] = useState<Essay[]>([]);
  const [activeEssayId, setActiveEssayId] = useState<string | null>(null);
  const [mode, setMode] = useState<PracticeMode>(PracticeMode.READ);

  // State for adding new essay
  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [newTitle, setNewTitle] = useState('');
  const [newContent, setNewContent] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);

  // State for practice
  const [answers, setAnswers] = useState<UserAnswers>({});
  const [results, setResults] = useState<VerificationResult | null>(null);
  const [score, setScore] = useState<number | null>(null);

  // State for Audio
  const [isPlaying, setIsPlaying] = useState(false);
  const [isLoadingAudio, setIsLoadingAudio] = useState(false);
  const shouldPlayRef = useRef(false);

  // Initialization
  useEffect(() => {
    const savedEssays = localStorage.getItem('memomaster_essays');
    if (savedEssays) {
      const parsed = JSON.parse(savedEssays);
      setEssays(parsed);
      if (parsed.length > 0) setActiveEssayId(parsed[0].id);
    } else {
      // Load initial essay
      const initialId = generateId();
      const initialEssay: Essay = {
        id: initialId,
        title: INITIAL_ESSAY_TITLE,
        rawContent: INITIAL_ESSAY_CONTENT,
        tokens: [],
        isAnalyzed: false,
        createdAt: Date.now()
      };
      setEssays([initialEssay]);
      setActiveEssayId(initialId);
      analyzeEssay(initialEssay);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Save to local storage whenever essays change
  useEffect(() => {
    if (essays.length > 0) {
      localStorage.setItem('memomaster_essays', JSON.stringify(essays));
    }
  }, [essays]);

  // Reset answers and STOP AUDIO when mode or essay changes
  useEffect(() => {
    setAnswers({});
    setResults(null);
    setScore(null);

    // Stop audio
    shouldPlayRef.current = false;
    stopAudio();
    setIsPlaying(false);

  }, [mode, activeEssayId]);

  const activeEssay = essays.find(e => e.id === activeEssayId);

  const analyzeEssay = async (essay: Essay) => {
    setIsProcessing(true);
    try {
      const tokens = await analyzeTextForMemorization(essay.rawContent);
      setEssays(prev => prev.map(e => e.id === essay.id ? { ...e, tokens, isAnalyzed: true } : e));
    } catch (err) {
      alert("Failed to analyze text. Please check API Key and try again.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleAddEssay = async () => {
    if (!newTitle.trim() || !newContent.trim()) return;

    setIsProcessing(true);
    try {
      const tokens = await analyzeTextForMemorization(newContent);
      const newEssay: Essay = {
        id: generateId(),
        title: newTitle,
        rawContent: newContent,
        tokens,
        isAnalyzed: true,
        createdAt: Date.now()
      };
      setEssays(prev => [...prev, newEssay]);
      setActiveEssayId(newEssay.id);
      setIsAddModalOpen(false);
      setNewTitle('');
      setNewContent('');
      setMode(PracticeMode.READ);
    } catch (err) {
      alert("Failed to process essay. Ensure API Key is set.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleDeleteEssay = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (window.confirm("Are you sure you want to delete this essay?")) {
        const newEssays = essays.filter(ex => ex.id !== id);
        setEssays(newEssays);
        localStorage.setItem('memomaster_essays', JSON.stringify(newEssays));
        if (activeEssayId === id) {
            setActiveEssayId(newEssays.length > 0 ? newEssays[0].id : null);
        }
    }
  };

  const handlePlayAudio = async () => {
    if (!activeEssay) return;

    // Toggle off
    if (isPlaying) {
        shouldPlayRef.current = false;
        stopAudio();
        // setIsPlaying(false) happens automatically via playAudioBuffer promise resolution when stopped
        return;
    }

    shouldPlayRef.current = true;
    setIsLoadingAudio(true);
    try {
        const base64 = await generateSpeech(activeEssay.rawContent);

        // Check if user cancelled or switched away while waiting for API
        if (!shouldPlayRef.current) {
            setIsLoadingAudio(false);
            return;
        }

        const ctx = getAudioContext();
        const buffer = await decodeAudioData(base64, ctx);

        // Check again
        if (!shouldPlayRef.current) {
            setIsLoadingAudio(false);
            return;
        }

        setIsLoadingAudio(false);
        setIsPlaying(true);
        await playAudioBuffer(buffer);
        setIsPlaying(false);
        shouldPlayRef.current = false;
    } catch (err) {
        console.error(err);
        if (shouldPlayRef.current) {
            alert("Audio generation failed.");
            setIsLoadingAudio(false);
            setIsPlaying(false);
            shouldPlayRef.current = false;
        }
    }
  };

  const isTokenHidden = (token: Token) => {
    if (token.isSeparator) return false;

    const p = token.pos;
    if (mode === PracticeMode.READ) return false;

    // Level 1: Nouns
    if (mode === PracticeMode.LEVEL_1) {
        return p === 'noun';
    }

    // Level 2: Nouns + Verbs
    if (mode === PracticeMode.LEVEL_2) {
        return p === 'noun' || p === 'verb';
    }

    // Level 3: Nouns + Verbs + Adj + Adv
    if (mode === PracticeMode.LEVEL_3) {
        return p === 'noun' || p === 'verb' || p === 'adj' || p === 'adv';
    }

    return false;
  };

  const handleInputChange = (id: string, value: string) => {
    setAnswers(prev => ({ ...prev, [id]: value }));
  };

  const checkAnswers = () => {
    if (!activeEssay) return;

    let correctCount = 0;
    let totalHidden = 0;
    const newResults: VerificationResult = {};

    activeEssay.tokens.forEach(token => {
        if (isTokenHidden(token)) {
            totalHidden++;
            const userVal = (answers[token.id] || "").trim().toLowerCase();
            const correctVal = token.text.trim().toLowerCase();

            // Allow for minor punctuation mismatch if user typed it, though usually we just check the word
            // Let's strip punctuation from both for comparison to be safe
            const cleanUser = userVal.replace(/[.,/#!$%^&*;:{}=\-_`~()]/g,"");
            const cleanCorrect = correctVal.replace(/[.,/#!$%^&*;:{}=\-_`~()]/g,"");

            const isCorrect = cleanUser === cleanCorrect;
            newResults[token.id] = isCorrect;
            if (isCorrect) correctCount++;
        }
    });

    setResults(newResults);
    setScore(totalHidden === 0 ? 100 : Math.round((correctCount / totalHidden) * 100));
  };

  // --- Render Helpers ---

  const renderToken = (token: Token) => {
    if (token.isSeparator) {
        // Replace newlines with <br/>
        if (token.text.includes('\n')) {
             return <br key={token.id} />;
        }
        return <span key={token.id} className="whitespace-pre">{token.text}</span>;
    }

    const hidden = isTokenHidden(token);

    if (hidden) {
        const isChecked = results !== null;
        const isCorrect = isChecked ? results[token.id] : undefined;

        let borderClass = "border-gray-300 focus:border-blue-500";
        let textClass = "text-gray-800";

        if (isChecked) {
            borderClass = isCorrect ? "border-green-500 bg-green-50" : "border-red-500 bg-red-50";
            textClass = isCorrect ? "text-green-700" : "text-red-700";
        }

        // Calculate width approx based on char length, min 30px
        const width = Math.max(30, token.text.length * 10) + "px";

        return (
            <span key={token.id} className="inline-block mx-1 relative group">
                <input
                    type="text"
                    value={answers[token.id] || ''}
                    onChange={(e) => handleInputChange(token.id, e.target.value)}
                    className={`border-b-2 outline-none text-center bg-transparent transition-colors px-1 ${borderClass} ${textClass}`}
                    style={{ width }}
                    autoComplete="off"
                    autoCorrect="off"
                    autoCapitalize="off"
                />
                {isChecked && !isCorrect && (
                     <span className="absolute -top-6 left-1/2 -translate-x-1/2 bg-black text-white text-xs px-2 py-1 rounded opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none whitespace-nowrap z-10">
                        {token.text}
                     </span>
                )}
            </span>
        );
    }

    return <span key={token.id} className="text-gray-800">{token.text}</span>;
  };

  // --- Main Render ---

  return (
    <div className="flex h-screen overflow-hidden bg-gray-50">

      {/* Sidebar */}
      <aside className="w-64 bg-white border-r border-gray-200 flex flex-col hidden md:flex">
        <div className="p-4 border-b border-gray-100 flex items-center justify-between">
            <h1 className="font-bold text-xl text-blue-600 tracking-tight">MemoMaster AI</h1>
        </div>

        <div className="flex-1 overflow-y-auto p-2 space-y-1 no-scrollbar">
            {essays.map(essay => (
                <div
                    key={essay.id}
                    onClick={() => setActiveEssayId(essay.id)}
                    className={`group flex items-center justify-between p-3 rounded-lg cursor-pointer transition-all ${
                        activeEssayId === essay.id ? 'bg-blue-50 text-blue-700 font-medium' : 'hover:bg-gray-100 text-gray-600'
                    }`}
                >
                    <span className="truncate pr-2">{essay.title}</span>
                    <button 
                        onClick={(e) => handleDeleteEssay(essay.id, e)}
                        className="text-gray-400 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-opacity"
                    >
                        <TrashIcon />
                    </button>
                </div>
            ))}
        </div>

        <div className="p-4 border-t border-gray-100">
            <button
                onClick={() => setIsAddModalOpen(true)}
                className="w-full flex items-center justify-center gap-2 bg-blue-600 hover:bg-blue-700 text-white py-2 px-4 rounded-lg font-medium transition-colors shadow-sm"
            >
                <PlusIcon /> New Essay
            </button>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col h-full relative">

        {/* Mobile Header */}
        <div className="md:hidden bg-white border-b p-4 flex justify-between items-center">
             <h1 className="font-bold text-lg text-blue-600">MemoMaster AI</h1>
             <button onClick={() => setIsAddModalOpen(true)} className="text-blue-600">
                 <PlusIcon />
             </button>
        </div>

        {/* Top Control Bar */}
        {activeEssay && (
        <header className="bg-white border-b border-gray-200 px-6 py-4 flex flex-col sm:flex-row sm:items-center justify-between gap-4 shadow-sm z-10">
            <div>
                <h2 className="text-2xl font-bold text-gray-800 truncate max-w-md">{activeEssay.title}</h2>
                <div className="text-sm text-gray-400 mt-1">
                    {activeEssay.tokens.length > 0 ? `${activeEssay.tokens.filter(t=>!t.isSeparator).length} words` : 'Processing...'}
                </div>
            </div>

            <div className="flex items-center gap-2 bg-gray-100 p-1 rounded-lg self-start sm:self-auto">
                <button
                    onClick={() => setMode(PracticeMode.READ)}
                    className={`px-4 py-1.5 rounded-md text-sm font-medium transition-all ${mode === PracticeMode.READ ? 'bg-white text-blue-600 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}
                >
                    Read
                </button>
                <button
                    onClick={() => setMode(PracticeMode.LEVEL_1)}
                    className={`px-4 py-1.5 rounded-md text-sm font-medium transition-all ${mode === PracticeMode.LEVEL_1 ? 'bg-white text-blue-600 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}
                >
                    Step 1 (N)
                </button>
                <button
                    onClick={() => setMode(PracticeMode.LEVEL_2)}
                    className={`px-4 py-1.5 rounded-md text-sm font-medium transition-all ${mode === PracticeMode.LEVEL_2 ? 'bg-white text-blue-600 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}
                >
                    Step 2 (V)
                </button>
                <button
                    onClick={() => setMode(PracticeMode.LEVEL_3)}
                    className={`px-4 py-1.5 rounded-md text-sm font-medium transition-all ${mode === PracticeMode.LEVEL_3 ? 'bg-white text-blue-600 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}
                >
                    Step 3 (All)
                </button>
            </div>
        </header>
        )}

        {/* Text Area */}
        <div className="flex-1 overflow-y-auto p-4 sm:p-8 bg-gray-50">
            <div className="max-w-3xl mx-auto bg-white rounded-2xl shadow-sm border border-gray-100 min-h-[50vh] p-6 sm:p-10 leading-loose text-lg text-gray-800">
                {activeEssay ? (
                    !activeEssay.isAnalyzed ? (
                        <div className="flex flex-col items-center justify-center h-40 text-gray-400">
                           <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-500 mb-2"></div>
                           <p>Analyzing grammar structure...</p>
                        </div>
                    ) : (
                        <div className="space-y-4">
                            <div className="font-serif leading-9">
                                {activeEssay.tokens.map(token => renderToken(token))}
                            </div>
                        </div>
                    )
                ) : (
                   <div className="text-center text-gray-400 mt-20">No essay selected. Create one to start.</div>
                )}
            </div>
        </div>

        {/* Bottom Sticky Action Bar */}
        {activeEssay && activeEssay.isAnalyzed && (
            <div className="absolute bottom-6 left-0 right-0 flex justify-center gap-4 px-4 pointer-events-none">
                <div className="bg-white/90 backdrop-blur-md shadow-lg border border-gray-200 rounded-full p-2 flex items-center gap-4 pointer-events-auto pr-6">

                    {/* Audio Control */}
                    <button 
                        onClick={handlePlayAudio}
                        disabled={isLoadingAudio}
                        className="w-10 h-10 rounded-full bg-gray-100 hover:bg-gray-200 flex items-center justify-center text-gray-700 transition-colors"
                        title="Read Aloud (Gemini TTS)"
                    >
                        {isLoadingAudio ? <LoadingSpinner /> : isPlaying ? <PauseIcon /> : <PlayIcon />}
                    </button>

                    <div className="w-px h-6 bg-gray-300"></div>

                    {/* Check Action (Only in practice modes) */}
                    {mode !== PracticeMode.READ && (
                         <div className="flex items-center gap-4">
                            {score !== null && (
                                <div className={`font-bold text-lg ${score > 80 ? 'text-green-600' : 'text-orange-500'}`}>
                                    {score}% Correct
                                </div>
                            )}
                            <button
                                onClick={checkAnswers}
                                className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-5 py-2 rounded-full font-medium shadow-md transition-transform active:scale-95"
                            >
                                <CheckIcon /> Check Answers
                            </button>
                         </div>
                    )}

                    {mode === PracticeMode.READ && (
                        <span className="text-sm text-gray-500 font-medium px-2">Read Mode</span>
                    )}

                </div>
            </div>
        )}

        {/* Add Modal */}
        {isAddModalOpen && (
            <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/40 backdrop-blur-sm p-4">
                <div className="bg-white rounded-xl shadow-2xl w-full max-w-lg overflow-hidden">
                    <div className="p-6">
                        <h3 className="text-xl font-bold text-gray-800 mb-4">Add New Essay</h3>
                        <div className="space-y-4">
                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Title</label>
                                <input
                                    type="text"
                                    value={newTitle}
                                    onChange={e => setNewTitle(e.target.value)}
                                    className="w-full border border-gray-300 rounded-lg px-4 py-2 focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none"
                                    placeholder="e.g. Unit 1: My School"
                                />
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Content</label>
                                <textarea
                                    value={newContent}
                                    onChange={e => setNewContent(e.target.value)}
                                    rows={8}
                                    className="w-full border border-gray-300 rounded-lg px-4 py-2 focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none resize-none"
                                    placeholder="Paste your essay here..."
                                />
                            </div>
                        </div>
                    </div>
                    <div className="bg-gray-50 px-6 py-4 flex justify-end gap-3 border-t border-gray-100">
                        <button
                            onClick={() => setIsAddModalOpen(false)}
                            className="px-4 py-2 text-gray-600 hover:bg-gray-200 rounded-lg font-medium transition-colors"
                        >
                            Cancel
                        </button>
                        <button
                            onClick={handleAddEssay}
                            disabled={isProcessing || !newTitle || !newContent}
                            className={`px-4 py-2 bg-blue-600 text-white rounded-lg font-medium shadow-sm transition-all flex items-center gap-2 ${
                                (isProcessing || !newTitle || !newContent) ? 'opacity-50 cursor-not-allowed' : 'hover:bg-blue-700'
                            }`}
                        >
                            {isProcessing ? <><LoadingSpinner /> Processing...</> : 'Add Essay'}
                        </button>
                    </div>
                </div>
            </div>
        )}

      </main>
    </div>
  );
}

export type PartOfSpeech = 'noun' | 'verb' | 'adj' | 'adv' | 'other';

export interface Token {
  id: string;
  text: string;
  pos: PartOfSpeech;
  isSeparator?: boolean; // spaces, punctuation, newlines
}

export interface Sentence {
  id: string;
  english: string;
  chinese: string;
}

export interface Essay {
  id: string;
  title: string;
  rawContent: string;
  tokens: Token[];
  sentences?: Sentence[]; // New field for translation mode
  isAnalyzed: boolean;
  createdAt: number;
}

export enum PracticeMode {
  READ = 'READ',
  LEVEL_1 = 'LEVEL_1', // Nouns
  LEVEL_2 = 'LEVEL_2', // Nouns + Verbs
  LEVEL_3 = 'LEVEL_3', // Nouns + Verbs + Adj + Adv
  TRANSLATION = 'TRANSLATION', // New mode: Chinese to English
}

export interface UserAnswers {
  [tokenId: string]: string;
}

export interface VerificationResult {
  [tokenId: string]: boolean;
}

