const DB_NAME = 'MemoMasterAudioDB';
const STORE_NAME = 'audio';
const DB_VERSION = 1;

export const openDB = (): Promise<IDBDatabase> => {
    return new Promise((resolve, reject) => {
        if (typeof window === 'undefined') {
            reject(new Error("IndexedDB not supported"));
            return;
        }
        const request = indexedDB.open(DB_NAME, DB_VERSION);
        request.onupgradeneeded = (event) => {
            const db = (event.target as IDBOpenDBRequest).result;
            if (!db.objectStoreNames.contains(STORE_NAME)) {
                db.createObjectStore(STORE_NAME);
            }
        };
        request.onsuccess = () => resolve(request.result);
        request.onerror = () => reject(request.error);
    });
};

export const saveAudioToDB = async (id: string, data: ArrayBuffer) => {
    const db = await openDB();
    return new Promise<void>((resolve, reject) => {
        const tx = db.transaction(STORE_NAME, 'readwrite');
        const store = tx.objectStore(STORE_NAME);
        const request = store.put(data, id);
        request.onsuccess = () => resolve();
        request.onerror = () => reject(request.error);
    });
};

export const getAudioFromDB = async (id: string): Promise<ArrayBuffer | undefined> => {
    const db = await openDB();
    return new Promise((resolve, reject) => {
        const tx = db.transaction(STORE_NAME, 'readonly');
        const store = tx.objectStore(STORE_NAME);
        const request = store.get(id);
        request.onsuccess = () => resolve(request.result);
        request.onerror = () => reject(request.error);
    });
};

export const hasAudioInDB = async (id: string): Promise<boolean> => {
    const db = await openDB();
    return new Promise((resolve, reject) => {
        const tx = db.transaction(STORE_NAME, 'readonly');
        const store = tx.objectStore(STORE_NAME);
        const request = store.count(id);
        request.onsuccess = () => resolve(request.result > 0);
        request.onerror = () => reject(request.error);
    });
};

import { GoogleGenAI, Modality, Type } from "@google/genai";
import { Token, Sentence } from "../types";

// Note: In a production app, never expose API keys on the client side.
// This is for demonstration purposes or personal tools.
const getClient = () => {
    const apiKey = process.env.API_KEY;
    if (!apiKey) {
        throw new Error("API Key is missing. Please set process.env.API_KEY.");
    }
    return new GoogleGenAI({ apiKey });
};

// Helper: Decode Base64 string to Uint8Array
const base64ToUint8Array = (base64: string): Uint8Array => {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

export const analyzeTextForMemorization = async (text: string): Promise<Token[]> => {
  const ai = getClient();

  const prompt = `
    Analyze the following English text for a fill-in-the-blank exercise.
    Break the text down into a sequence of tokens that can perfectly reconstruct the original text.

    For each token, assign a 'pos' (Part of Speech) from these categories:
    - 'noun'
    - 'verb' (including auxiliary verbs like 'is', 'are', 'can')
    - 'adj' (adjective)
    - 'adv' (adverb)
    - 'other' (prepositions, pronouns like 'it', 'they', conjunctions, articles, etc.)

    If the token is punctuation, space, or newline, label 'pos' as 'other' and mark 'isSeparator' as true.

    Text to analyze:
    """${text}"""
  `;

  try {
    const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: {
            responseMimeType: "application/json",
            responseSchema: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: {
                        text: { type: Type.STRING },
                        pos: { type: Type.STRING, enum: ['noun', 'verb', 'adj', 'adv', 'other'] },
                        isSeparator: { type: Type.BOOLEAN }
                    },
                    required: ['text', 'pos']
                }
            }
        }
    });

    const tokens = JSON.parse(response.text || '[]');

    // Add unique IDs to tokens for React keys
    return tokens.map((t: any, idx: number) => ({
        ...t,
        id: `token-${idx}-${Date.now()}`
    }));

  } catch (error) {
    console.error("Gemini Analysis Failed:", error);
    throw error;
  }
};

export const analyzeTextForTranslation = async (text: string): Promise<Sentence[]> => {
    const ai = getClient();

    const prompt = `
      Split the following English text into individual sentences. 
      For each sentence, provide a natural Chinese translation.
      Return a JSON array where each object has "english" and "chinese".

      Text to process:
      """${text}"""
    `;

    try {
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            english: { type: Type.STRING },
                            chinese: { type: Type.STRING }
                        },
                        required: ['english', 'chinese']
                    }
                }
            }
        });

        const data = JSON.parse(response.text || '[]');
        return data.map((item: any, idx: number) => ({
            id: `sent-${idx}-${Date.now()}`,
            english: item.english,
            chinese: item.chinese
        }));

    } catch (error) {
        console.error("Gemini Translation Analysis Failed:", error);
        throw error;
    }
}

export const generateSpeechForText = async (text: string): Promise<Uint8Array> => {
    const ai = getClient();

    // Use the specific TTS model
    const model = 'gemini-2.5-flash-preview-tts';

    try {
        const response = await ai.models.generateContent({
            model: model,
            contents: {
                parts: [{ text: text }]
            },
            config: {
                responseModalities: [Modality.AUDIO],
                speechConfig: {
                    voiceConfig: {
                        prebuiltVoiceConfig: { voiceName: 'Kore' }, // 'Kore' is a good, neutral voice
                    },
                },
            },
        });

        const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
        if (!base64Audio) {
            throw new Error("No audio data returned from Gemini.");
        }

        return base64ToUint8Array(base64Audio);

    } catch (error) {
        console.error("Gemini TTS Generation Failed:", error);
        throw error;
    }
}

// Utility to handle Text-to-Speech using native Web Speech API (Fallback)
// AND raw PCM playback for cached Gemini audio (Primary High-Quality Offline).

let synth: SpeechSynthesis | null = null;
if (typeof window !== "undefined") {
  synth = window.speechSynthesis;
}

// Global state
let audioCtx: AudioContext | null = null;
let currentSource: AudioBufferSourceNode | null = null;
let queue: string[] = [];
let onCompleteGlobal: (() => void) | null = null;
let isInternalPlaying = false;

// --- Web Speech API Helper (Fallback) ---
const getEnglishVoice = (): SpeechSynthesisVoice | null => {
  if (!synth) return null;
  const voices = synth.getVoices();
  return (
    voices.find((v) => v.name === "Google US English") ||
    voices.find((v) => v.name.includes("Samantha")) || 
    voices.find((v) => v.name.includes("Daniel")) ||   
    voices.find((v) => v.lang === "en-US") ||
    voices.find((v) => v.lang.startsWith("en")) ||
    null
  );
};

const chunkText = (text: string): string[] => {
  const rawSentences = text.match(/[^.!?\n]+[.!?\n]*/g) || [text];
  return rawSentences.map(s => s.trim()).filter(s => s.length > 0);
};

const speakNext = () => {
    if (!synth || queue.length === 0) {
        isInternalPlaying = false;
        if (onCompleteGlobal) onCompleteGlobal();
        return;
    }

    const text = queue.shift()!;
    const utterance = new SpeechSynthesisUtterance(text);
    const voice = getEnglishVoice();
    if (voice) utterance.voice = voice;
    utterance.rate = 0.9; 
    utterance.pitch = 1.0;
    utterance.onend = () => speakNext();
    utterance.onerror = (e) => {
        console.error("TTS Error:", e);
        speakNext();
    };
    synth.speak(utterance);
};

export const playText = (text: string, onComplete?: () => void) => {
    stopAudio();
    if (!synth) {
        if (onComplete) onComplete();
        return;
    }

    queue = chunkText(text);
    onCompleteGlobal = onComplete || null;
    isInternalPlaying = true;

    if (synth.getVoices().length === 0) {
        const tempHandler = () => {
            synth!.onvoiceschanged = null;
            if (isInternalPlaying) speakNext();
        };
        synth.onvoiceschanged = tempHandler;
        setTimeout(() => {
            if (isInternalPlaying && synth!.speaking === false) speakNext();
        }, 100);
    } else {
        speakNext();
    }
};

// --- Raw PCM Playback Helper (Primary High Quality) ---

// Decode raw PCM (24kHz, 1 channel, 16-bit)
async function decodePCM(
  buffer: ArrayBuffer,
  ctx: AudioContext,
  sampleRate: number = 24000
): Promise<AudioBuffer> {
  const numChannels = 1;
  const dataInt16 = new Int16Array(buffer);
  const frameCount = dataInt16.length / numChannels;
  const audioBuffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = audioBuffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      // Normalize Int16 (-32768 to 32767) to Float32 (-1.0 to 1.0)
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return audioBuffer;
}

export const playPCM = async (data: ArrayBuffer, onComplete?: () => void) => {
    stopAudio(); // Stop any TTS or other audio

    if (!audioCtx) {
        audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)();
    }

    // Gemini 2.5 TTS outputs at 24000Hz
    const buffer = await decodePCM(data, audioCtx, 24000);

    const source = audioCtx.createBufferSource();
    source.buffer = buffer;
    source.connect(audioCtx.destination);

    currentSource = source;
    isInternalPlaying = true;

    source.onended = () => {
        isInternalPlaying = false;
        currentSource = null;
        if (onComplete) onComplete();
    };

    source.start();
};

export const stopAudio = () => {
    isInternalPlaying = false;
    queue = [];
    onCompleteGlobal = null;

    // Stop Web Speech
    if (synth) synth.cancel();

    // Stop PCM Audio
    if (currentSource) {
        try {
            currentSource.stop();
        } catch(e) { /* ignore */ }
        currentSource = null;
    }
};

