  id: string;
  text: string;
  pos: PartOfSpeech;
  isSeparator?: boolean; // spaces, punctuation, newlines
}

export interface Sentence {
  id: string;
  english: string;
  chinese: string;
}

export interface Essay {
  id: string;
  title: string;
  rawContent: string;
  tokens: Token[];
  sentences?: Sentence[]; 
  isAnalyzed: boolean;
  createdAt: number;
  audioPath?: string; // Path to local audio file (e.g., /audio/filename.wav)
}

